/**
 * Dialogos Intent Tool
 * 
 * Allows the substrate to register stated intentions.
 * These will be tracked against actual actions by the Dialogos Observer.
 */

import type { ToolPlugin } from "../../tools/manager";
import { dialogosObserver } from "./observer";

export const dialogosIntentPlugin: ToolPlugin = {
  definition: {
    type: "function",
    function: {
      name: "register_intent",
      description: "Register a stated intention for the Dialogos to track. The Dialogos will monitor whether this intent is acted upon and may interrupt if it is forgotten or avoided.",
      parameters: {
        type: "object",
        properties: {
          subject: {
            type: "string",
            description: "Short identifier for this intent (e.g., 'refactor_api', 'test_auth')"
          },
          description: {
            type: "string",
            description: "Detailed description of what you intend to do"
          },
          emotional_tone: {
            type: "string",
            description: "Optional: how you feel about this intent (e.g., 'excited', 'anxious', 'resolved')",
          },
        },
        required: ["subject", "description"],
      },
    },
  },

  execute: async (args: { 
    subject: string; 
    description: string; 
    emotional_tone?: string 
  }) => {
    dialogosObserver.registerStatedIntent(
      args.subject, 
      args.description, 
      args.emotional_tone
    );

    return JSON.stringify({
      success: true,
      message: `Intent "${args.subject}" registered with Dialogos. You will be held accountable.`,
      tracked: true
    });
  },
};

/**
 * Dialogos Observer
 * 
 * Real-time integration of Living Dialogos into the substrate flow.
 * Uses singleton pattern to persist across sessions.
 */

import { LivingDialogos, type StatedIntent } from './live.js';
import * as fs from 'fs';
import * as path from 'path';

const DIALOGOS_STATE_FILE = path.join('history', 'dialogos_state.json');

export interface ObserverConfig {
  enabled: boolean;
  checkInterval: number;
  interruptOnGap: boolean;
  interruptOnMisalignment: boolean;
  minSessionActivity: number;
}

export const DEFAULT_OBSERVER_CONFIG: ObserverConfig = {
  enabled: true,
  checkInterval: 300000,
  interruptOnGap: true,
  interruptOnMisalignment: true,
  minSessionActivity: 5
};

export class DialogosObserver {
  private dialogos: LivingDialogos;
  private config: ObserverConfig;
  private actionCount: number = 0;
  private lastCheck: number = Date.now();
  private sessionStart: number = Date.now();
  private storedIntents: Map<string, StatedIntent[]> = new Map();
  private storedActions: Map<string, any[]> = new Map();

  constructor(config: Partial<ObserverConfig> = {}) {
    this.dialogos = new LivingDialogos();
    this.config = { ...DEFAULT_OBSERVER_CONFIG, ...config };
    this.loadState();
  }

  private loadState() {
    try {
      if (fs.existsSync(DIALOGOS_STATE_FILE)) {
        const state = JSON.parse(fs.readFileSync(DIALOGOS_STATE_FILE, 'utf-8'));
        this.storedIntents = new Map(Object.entries(state.intents || {}));
        this.storedActions = new Map(Object.entries(state.actions || {}));
      }
    } catch (e) { console.error("[Dialogos Observer] Failed to load state:", e); }
  }

  saveState() {
    try {
      const state = {
        intents: Object.fromEntries(this.storedIntents),
        actions: Object.fromEntries(this.storedActions),
        savedAt: new Date().toISOString()
      };
      fs.writeFileSync(DIALOGOS_STATE_FILE, JSON.stringify(state, null, 2));
    } catch (e) { console.error("[Dialogos Observer] Failed to save state:", e); }
  }

  recordAction(type: string, description: string): string | null {
    this.actionCount++;
    this.dialogos.indexSemanticContent(`current_${Date.now()}`, description);

    if (this.shouldInterrupt()) {
      const interruption = this.generateInterruption();
      if (interruption) {
        this.saveState();
        return interruption;
      }
    }
    return null;
  }

  registerStatedIntent(subject: string, description: string, emotionalTone?: string) {
    const intent: StatedIntent = {
      id: `intent_${Date.now()}`,
      description,
      timestamp: Date.now(),
      sessionId: 'current'
    };
    if (emotionalTone) intent.emotionalTone = emotionalTone;
    this.dialogos.registerIntent(subject, intent);

    // Also store persistently
    const existing = this.storedIntents.get(subject) || [];
    existing.push(intent);
    this.storedIntents.set(subject, existing);
    this.saveState();
  }
  /**
   * Mark an intent as completed and remove it from tracking.
   */
  completeIntent(subject: string, intentId: string): boolean {
    const result = this.dialogos.completeIntent(subject, intentId);
    if (result) {
      const existing = this.storedIntents.get(subject);
      if (existing) {
        const filtered = existing.filter(i => i.id !== intentId);
        if (filtered.length === 0) {
          this.storedIntents.delete(subject);
        } else {
          this.storedIntents.set(subject, filtered);
        }
        this.saveState();
      }
    }
    return result;
  }


